package main

import (
    "fmt"
    "strconv"
)

func main() {
    // Numeric
    var i int = 42
    var f float64 = float64(i)
    fmt.Printf("int %d to float64 %f\n", i, f)

    // String conv
    num := strconv.Itoa(123)
    val, _ := strconv.Atoi("456")
    fmt.Println(num, val)

    // Bytes
    s := "Go"
    bytes := []byte(s)
    fmt.Println(bytes)
}
